if('serviceWorker' in navigator){window.addEventListener('load',function(){navigator.serviceWorker.register('/sw.js').then(function(registration){console.log('SW registered: ',registration)}).catch(function(registrationError){console.log('SW registration failed: ',registrationError)})})}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function(){document.querySelector('body').classList.add('loaded')})}else{document.querySelector('body').classList.add('loaded')}
document.addEventListener('DOMContentLoaded',function(){const newsletterPopup=document.getElementById('newsletter-popup-form');if(!newsletterPopup){return}
if(localStorage.getItem('ipmc_newsletter_shown')){return}
const showPopup=function(){if(localStorage.getItem('ipmc_newsletter_shown')){return}
if(typeof $!=='undefined'&&$.magnificPopup){$.magnificPopup.open({items:{src:'#newsletter-popup-form',type:'inline'},mainClass:'mfp-newsletter',removalDelay:300,callbacks:{beforeOpen:function(){localStorage.setItem('ipmc_newsletter_shown','true')},close:function(){localStorage.setItem('ipmc_newsletter_shown','true')}}})}};setTimeout(showPopup,5000);const newsletterForm=newsletterPopup.querySelector('form');if(newsletterForm){newsletterForm.addEventListener('submit',async function(e){e.preventDefault();const emailInput=newsletterForm.querySelector('#newsletter-email')||newsletterForm.querySelector('input[type="email"]');const nameInput=newsletterForm.querySelector('#newsletter-name')||newsletterForm.querySelector('input[name="name"]');const email=emailInput?emailInput.value.trim():'';const name=nameInput?nameInput.value.trim():'';if(!window.Utils||!window.Utils.isValidEmail||!window.Utils.isValidEmail(email)){if(emailInput)emailInput.focus();return alert('Please enter a valid email address.')}
try{const res=await fetch('/api/newsletter/subscribe',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email,name})});const data=await res.json();localStorage.setItem('ipmc_newsletter_shown','true');if(typeof $!=='undefined'&&$.magnificPopup){$.magnificPopup.close()}
if(res.ok){console.log('Newsletter subscribed:',data)}else{console.warn('Newsletter subscribe failed:',data);alert(data.message||'Subscription failed.')}}catch(err){console.error('Newsletter subscribe error:',err);alert('Subscription failed. Please try again later.')}})}
const showAgainCheckbox=document.getElementById('show-again');if(showAgainCheckbox){showAgainCheckbox.addEventListener('change',function(){if(this.checked){localStorage.setItem('ipmc_newsletter_shown','true');if(typeof $!=='undefined'&&$.magnificPopup){$.magnificPopup.close()}}})}})